document.addEventListener('DOMContentLoaded', () => {
const header = document.querySelector('.site-header');
window.addEventListener('scroll', () => {
if (window.scrollY > 50) {
header.classList.add('scrolled');
} else {
header.classList.remove('scrolled');
}
});
const menuToggle = document.querySelector('.menu-toggle');
const mobileDrawer = document.querySelector('.mobile-drawer');
const drawerLinks = document.querySelectorAll('.mobile-drawer a');
if (menuToggle && mobileDrawer) {
menuToggle.addEventListener('click', () => {
mobileDrawer.classList.toggle('active');
const isActive = mobileDrawer.classList.contains('active');
menuToggle.setAttribute('aria-expanded', isActive);
const spans = menuToggle.querySelectorAll('span');
if (isActive) {
spans[0].style.transform = 'rotate(45deg) translate(5px, 5px)';
spans[1].style.opacity = '0';
spans[2].style.transform = 'rotate(-45deg) translate(6px, -6px)';
} else {
spans[0].style.transform = 'none';
spans[1].style.opacity = '1';
spans[2].style.transform = 'none';
}
});
drawerLinks.forEach(link => {
link.addEventListener('click', () => {
mobileDrawer.classList.remove('active');
menuToggle.setAttribute('aria-expanded', 'false');
const spans = menuToggle.querySelectorAll('span');
spans[0].style.transform = 'none';
spans[1].style.opacity = '1';
spans[2].style.transform = 'none';
});
});
}
const faqItems = document.querySelectorAll('.faq-item');
faqItems.forEach(item => {
const header = item.querySelector('.faq-header');
const body = item.querySelector('.faq-body');
header.addEventListener('click', () => {
const isActive = item.classList.contains('active');
faqItems.forEach(otherItem => {
if (otherItem !== item) {
otherItem.classList.remove('active');
otherItem.querySelector('.faq-body').style.maxHeight = null;
}
});
if (isActive) {
item.classList.remove('active');
body.style.maxHeight = null;
} else {
item.classList.add('active');
body.style.maxHeight = body.scrollHeight + 'px';
}
});
});
const scannerBtn = document.querySelector('.scanner-btn');
const scannerInput = document.querySelector('.scanner-input');
const progressBar = document.querySelector('.scan-line-progress');
const statusText = document.querySelector('.scan-status-text');
const outputList = document.querySelector('.scan-output-list');
if (scannerBtn && scannerInput) {
scannerBtn.addEventListener('click', () => {
const urlValue = scannerInput.value.trim().toLowerCase();
if (!urlValue) return;
progressBar.style.width = '0%';
statusText.textContent = 'Inicializando anÃ¡lisis de seguridad...';
statusText.style.color = 'var(--accent)';
outputList.innerHTML = '';
scannerBtn.disabled = true;
let progress = 0;
const interval = setInterval(() => {
progress += 10;
progressBar.style.width = progress + '%';
if (progress === 30) {
statusText.textContent = 'Analizando estructura del dominio...';
addOutputLine('âœ“ Formato de dominio vÃ¡lido detectado', 'success');
} else if (progress === 60) {
statusText.textContent = 'Verificando firmas y certificados SSL...';
addOutputLine('âœ“ CertificaciÃ³n de cifrado HTTPS validada', 'success');
} else if (progress === 90) {
statusText.textContent = 'Contrastando con el registro oficial de Bancamiga...';
} else if (progress >= 100) {
clearInterval(interval);
scannerBtn.disabled = false;
evaluateDomain(urlValue);
}
}, 250);
});
}
function addOutputLine(text, className) {
const li = document.createElement('li');
li.className = className || '';
if (className === 'success') {
li.innerHTML = `<span>âœ“</span> ${text}`;
} else if (className === 'error') {
li.innerHTML = `<span style="color: #ff7659">âœ—</span> ${text}`;
} else {
li.textContent = text;
}
outputList.appendChild(li);
}
function evaluateDomain(domain) {
let cleanDomain = domain.replace(/^(https?:\/\/)?(www\.)?/, '');
cleanDomain = cleanDomain.split('/')[0];
const officialDomains = ['bancamiga.com', 'bancamiga.com.ve'];
if (officialDomains.includes(cleanDomain)) {
progressBar.style.background = 'var(--primary)';
statusText.textContent = 'Â¡ACCESO DIRECTO SEGURO Y VERIFICADO!';
statusText.style.color = 'var(--primary)';
addOutputLine('Canal oficial de Bancamiga Universal C.A. coincidente.', 'success');
addOutputLine('ConexiÃ³n encriptada TLS de alta seguridad.', 'success');
addOutputLine('Puedes ingresar tus datos con total confianza en este portal oficial.', 'success');
} else {
progressBar.style.background = '#ff7659';
statusText.textContent = 'Â¡ALERTA: SITIO NO OFICIAL O DESCONOCIDO!';
statusText.style.color = '#ff7659';
addOutputLine('El dominio analizado no pertenece a los servidores de Bancamiga.', 'error');
addOutputLine('Riesgo de phishing o suplantaciÃ³n de identidad detectado.', 'error');
addOutputLine('Evita introducir nombres de usuario, claves o tokens SMS en este enlace.', 'error');
}
}
});
